module johnson_counter_8bit(
    input clk,
    input rst,
    output [7:0] count
);

    reg [7:0] reset_reg;

    always @(posedge clk) begin
        if (rst) begin
            reset_reg <= 8'b11111111;
        end else begin
            reset_reg <= {reset_reg[6:0], ~reset_reg[7]};
        end
    end

    assign count = reset_reg;

endmodule
